- RLS를 통해 anon 키로는 읽기만 가능하고 쓰기는 API 라우트에서만 가능하도록 제한

## 구현 내용

### frontend/lib/notion.ts 수정

기존 파일에 다음 함수들 추가:

```typescript
import type { Brand, Capsule } from '@/types';

// Notion 페이지 속성 안전하게 추출하는 헬퍼
function getPlainText(property: any): string {
  if (property?.type === 'title') {
    return property.title.map((t: any) => t.plain_text).join('') || '';
  }
  if (property?.type === 'rich_text') {
    return property.rich_text.map((t: any) => t.plain_text).join('') || '';
  }
  return '';
}

function getNumber(property: any): number | null {
  return property?.type === 'number' ? property.number : null;
}

function getUrl(property: any): string | null {
  return property?.type === 'url' ? property.url : null;
}

function getRelation(property: any): string[] {
  if (property?.type === 'relation') {
    return property.relation.map((r: any) => r.id);
  }
  return [];
}

// Notion 페이지 → Brand 변환
function mapNotionPageToBrand(page: any): Brand {
  const props = page.properties;
  return {
    id: page.id,
    slug: getPlainText(props.slug || props.Slug),
    name: getPlainText(props.name || props.Name),
    description: getPlainText(props.description || props.Description),
    logoUrl: getUrl(props.logo_url || props['Logo URL']) || null,
    websiteUrl: getUrl(props.website_url || props['Website URL']) || null,
    country: getPlainText(props.country || props.Country),
    capsuleCount: getNumber(props.capsule_count || props['Capsule Count']) || 0,
  };
}

// Notion 페이지 → Capsule 변환
function mapNotionPageToCapsule(page: any): Capsule {
  const props = page.properties;
  const flavorNotes = getPlainText(props.flavor_notes || props['Flavor Notes']);

  return {
    id: page.id,
    slug: getPlainText(props.slug || props.Slug),
    brandId: getRelation(props.brand || props.Brand)[0] || '',
    name: getPlainText(props.name || props.Name),
    intensity: getNumber(props.intensity || props.Intensity) || 0,
    flavorNotes: flavorNotes ? flavorNotes.split(',').map(s => s.trim()) : [],
    imageUrl: getUrl(props.image_url || props['Image URL']) || null,
    isLimited: props.is_limited?.checkbox || false,
    averageRating: getNumber(props.average_rating || props['Average Rating']) || null,
  };
}

// 모든 브랜드 조회
export async function getBrands(): Promise<Brand[]> {
  try {
    const response = await notion.databases.query({
      database_id: BRAND_DATABASE_ID,
      sorts: [{ property: 'name', direction: 'ascending' }],
    });

    return response.results.map(mapNotionPageToBrand);
  } catch (error) {
    console.error('Notion getBrands error:', error);
    return [];
  }
}

// slug로 단일 브랜드 조회
export async function getBrandBySlug(slug: string): Promise<Brand | null> {
  try {
    const response = await notion.databases.query({
      database_id: BRAND_DATABASE_ID,
      filter: {
        property: 'slug',
        rich_text: { equals: slug },
      },
    });

    if (response.results.length === 0) return null;
    return mapNotionPageToBrand(response.results[0]);
  } catch (error) {
    console.error('Notion getBrandBySlug error:', error);
    return null;
  }
}

// 특정 브랜드의 캡슐 목록 조회
export async function getCapsulesByBrandId(brandId: string): Promise<Capsule[]> {
  try {
    const response = await notion.databases.query({
      database_id: CAPSULE_DATABASE_ID,
      filter: {
        property: 'brand',
        relation: { contains: brandId },
      },
      sorts: [{ property: 'name', direction: 'ascending' }],
    });

    return response.results.map(mapNotionPageToCapsule);
  } catch (error) {
    console.error('Notion getCapsulesByBrandId error:', error);
    return [];
  }
}

// slug로 단일 캡슐 조회
export async function getCapsuleBySlug(slug: string): Promise<Capsule | null> {
  try {
    const response = await notion.databases.query({
      database_id: CAPSULE_DATABASE_ID,
      filter: {
        property: 'slug',
        rich_text: { equals: slug },
      },
    });

    if (response.results.length === 0) return null;
    return mapNotionPageToCapsule(response.results[0]);
  } catch (error) {
    console.error('Notion getCapsuleBySlug error:', error);
    return null;
  }
}
```

## 주의사항
- Notion DB의 실제 프로퍼티명이 코드와 다를 수 있으므로 대소문자 및 공백 variation 처리
- ISR 캐싱은 페이지 단에서 `export const revalidate = 3600` 설정
- 에러 발생 시 빈 배열/null 반환하여 페이지가 깨지지 않도록 방어적 코딩

