const [turnstileToken, setTurnstileToken] = useState<string>('');

// ... 기존 코드 ...

const onSubmit = async (values: FormValues) => {
  if (!turnstileToken) {
    toast.error('CAPTCHA 인증을 완료해주세요.');
    return;
  }

  setIsSubmitting(true);
  try {
