### 1. ReviewList 컴포넌트를 서버 컴포넌트로 전환

`frontend/components/review/review-list.tsx` 수정:

```typescript
import { createServerSupabaseClient } from '@/lib/supabase';
import type { Review } from '@/types';
import { StarRating } from './star-rating';
import { formatDistanceToNow } from 'date-fns';
import { ko } from 'date-fns/locale';

interface ReviewListProps {
  capsuleSlug: string;
}

export async function ReviewList({ capsuleSlug }: ReviewListProps) {
  const supabase = createServerSupabaseClient();

  const { data: reviews, error } = await supabase
    .from('reviews')
    .select('*')
    .eq('capsule_slug', capsuleSlug)
    .order('created_at', { ascending: false });

  if (error) {
    console.error('리뷰 조회 실패:', error);
    return (
      <p className="text-center text-muted-foreground py-6">
        리뷰를 불러오는 중 오류가 발생했습니다.
      </p>
    );
  }

  if (!reviews || reviews.length === 0) {
    return (
      <p className="text-center text-muted-foreground py-6">
        아직 리뷰가 없습니다. 첫 번째 리뷰를 작성해보세요!
      </p>
    );
  }

  return (
    <div className="space-y-4">
      {reviews.map((review) => (
        <div key={review.id} className="border rounded-lg p-4">
          <div className="flex items-start justify-between mb-2">
            <div>
              <p className="font-semibold">{review.author_nickname}</p>
              <StarRating value={review.rating} size="sm" />
            </div>
            <p className="text-sm text-muted-foreground">
              {formatDistanceToNow(new Date(review.created_at), {
                addSuffix: true,
                locale: ko,
              })}
            </p>
          </div>
          <p className="text-sm">{review.content}</p>
        </div>
      ))}
    </div>
  );
}
```

