```typescript
import { createServerSupabaseClient } from '@/lib/supabase';
import { PostList } from '@/components/community/post-list';
import { Button } from '@/components/ui/button';
import Link from 'next/link';

export const revalidate = 60; // 1분마다 revalidate

interface Props {
  searchParams: Promise<{ category?: string }>;
}

export default async function CommunityPage({ searchParams }: Props) {
  const params = await searchParams;
  const category = params.category;

  const supabase = createServerSupabaseClient();

  let query = supabase
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false });

  if (category && ['정보공유', '추천', '질문', '잡담'].includes(category)) {
    query = query.eq('category', category);
  }

  const { data: posts, error } = await query;

  if (error) {
    console.error('게시글 조회 실패:', error);
  }

  return (
    <div className="mx-auto max-w-4xl px-4 py-10">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-3xl font-bold">커뮤니티</h1>
        <Link href="/community/write">
          <Button>글쓰기</Button>
        </Link>
      </div>

      {/* 카테고리 탭 */}
      <div className="flex gap-2 mb-6">
        {['전체', '정보공유', '추천', '질문', '잡담'].map((cat) => (
          <Link
            key={cat}
            href={cat === '전체' ? '/community' : `/community?category=${cat}`}
          >
            <Button variant={category === cat || (!category && cat === '전체') ? 'default' : 'outline'}>
              {cat}
            </Button>
          </Link>
        ))}
      </div>

      {posts && posts.length > 0 ? (
        <PostList posts={posts} />
      ) : (
        <p className="text-center text-muted-foreground py-10">
          아직 게시글이 없습니다.
        </p>
      )}
    </div>
  );
}
```

