#### 2. 클라이언트 컴포넌트 생성 (frontend/components/capsule/capsule-list-with-filters.tsx)

```typescript
"use client";

import { useState, useMemo } from 'react';
import type { Capsule } from '@/types';
import { CapsuleGrid } from './capsule-grid';
import { CapsuleSearch } from './capsule-search';
import { IntensityFilter } from './intensity-filter';

interface Props {
  capsules: Capsule[];
}

export function CapsuleListWithFilters({ capsules }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedIntensity, setSelectedIntensity] = useState<number | null>(null);

  const filteredCapsules = useMemo(() => {
    let result = capsules;

    // 검색어 필터링
    if (searchQuery.trim()) {
      result = result.filter((capsule) =>
        capsule.name.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    // 강도 필터링
    if (selectedIntensity !== null) {
      result = result.filter((capsule) => capsule.intensity === selectedIntensity);
    }

    return result;
  }, [capsules, searchQuery, selectedIntensity]);

  return (
    <div>
      <div className="mb-6 flex flex-col sm:flex-row gap-4">
        <div className="flex-1">
          <CapsuleSearch onSearch={setSearchQuery} />
        </div>
        <IntensityFilter
          onSelect={setSelectedIntensity}
          selectedIntensity={selectedIntensity}
        />
      </div>

      {filteredCapsules.length > 0 ? (
        <CapsuleGrid capsules={filteredCapsules} />
      ) : (
        <p className="text-center text-muted-foreground py-10">
          {searchQuery || selectedIntensity !== null
            ? '검색 조건에 맞는 캡슐이 없습니다.'
            : '등록된 캡슐이 없습니다.'}
        </p>
      )}
    </div>
  );
}
```

